import{c as a,Q as e,j as o,m as n}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"解释器系列总览索引","description":"","frontmatter":{},"headers":[],"relativePath":"interpreterLearning/99-总览索引.md","filePath":"interpreterLearning/99-总览索引.md","lastUpdated":1778496697000}'),r={name:"interpreterLearning/99-总览索引.md"};function s(d,t,c,l,i,p){return e(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="解释器系列总览索引" tabindex="-1">解释器系列总览索引 <a class="header-anchor" href="#解释器系列总览索引" aria-label="Permalink to &quot;解释器系列总览索引&quot;">​</a></h1><blockquote><p>30 篇文章的地图。先看这一页,挑你最关心的那条线钻进去。</p></blockquote><hr><h2 id="系列简介" tabindex="-1">系列简介 <a class="header-anchor" href="#系列简介" aria-label="Permalink to &quot;系列简介&quot;">​</a></h2><p>写一行 <code>let x = 1 + 2</code>,背后是 JS / Python / Lua / Ruby 共用的那层运行时——几千行代码协作把字符串变 token、变 AST、走求值或字节码 VM。<strong>这套机制几乎每门动态语言都长一样</strong>,亲手写一遍就等于一次性拆掉那层抽象。</p><p>本系列<strong>不是《Crafting Interpreters》翻译</strong>——那本书结构是教学,先把整本 Lox 一次性走完;<strong>本系列偏&quot;工程师视角&quot;</strong>:每篇对应一门语言里你天天用、却没拆过的特性,讲清楚它怎么实现、工业级怎么做、有哪些优化方向。</p><p>贯穿始终是一门玩具语言 <strong>Mochi</strong>(麻糬,软糯 Q 弹):动态类型、一等公民函数 + 闭包 + 类 + 模块,从 01-19 篇的树遍历版本一路推到 20-25 篇的字节码 VM,再在 26-27 篇加 GC。<strong>宿主语言 TypeScript 为主</strong>,关键算法附 Rust。</p><p><strong>完成判据</strong>:每篇都要 Mochi 仓库有对应 commit、文章里至少一张图、「工业级是怎么做的」给出 V8 / CPython / Lua / JVM 的具体文件路径——没指针就是没看源码,不能糊弄。</p><hr><h2 id="六层结构" tabindex="-1">六层结构 <a class="header-anchor" href="#六层结构" aria-label="Permalink to &quot;六层结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智与基础 → 前端 → 树遍历解释器 → 进阶语义 → 字节码虚拟机 → 运行时与未来</span></span></code></pre></div><table tabindex="0"><thead><tr><th>层</th><th>篇号</th><th>一句话</th></tr></thead><tbody><tr><td>第一层 心智与基础</td><td>01-04</td><td>看完知道&quot;语言运行时不是魔法,是几千行代码&quot;——为 Mochi 搭基建</td></tr><tr><td>第二层 前端</td><td>05-09</td><td>手痒值最高的一层——写完能解析任意小语言</td></tr><tr><td>第三层 树遍历解释器</td><td>10-15</td><td><strong>Mochi 第一次跑起来</strong>——REPL 打 Hello World 那一刻最爽</td></tr><tr><td>第四层 进阶语义</td><td>16-19</td><td>OOP / 模块 / 类型 / 元编程在实现层根本没你想的复杂</td></tr><tr><td>第五层 字节码虚拟机</td><td>20-25</td><td><strong>Mochi 性能爆炸的一层</strong>——实测比树遍历快 5-10 倍</td></tr><tr><td>第六层 运行时与未来</td><td>26-30</td><td><strong>最值钱的一层</strong>——读 V8 / CPython 源码从此不慌</td></tr></tbody></table><hr><h2 id="_30-篇地图" tabindex="-1">30 篇地图 <a class="header-anchor" href="#_30-篇地图" aria-label="Permalink to &quot;30 篇地图&quot;">​</a></h2><h3 id="第一层-心智与基础-01-04" tabindex="-1">第一层:心智与基础(01-04) <a class="header-anchor" href="#第一层-心智与基础-01-04" aria-label="Permalink to &quot;第一层:心智与基础(01-04)&quot;">​</a></h3><ul><li><a href="./01-解释器总览">01-解释器总览</a> —— 为什么写解释器是元能力;解释器 vs 编译器 vs JIT 三种姿态;一张图看清源码到结果的 5 个站点</li><li><a href="./02-一段代码怎么跑起来">02-一段代码怎么跑起来</a> —— <code>print(1+2)</code> 这一行从字符串到屏幕上 <code>3</code> 的全过程;每一步贴一个数据结构 snapshot</li><li><a href="./03-介绍Mochi">03-介绍Mochi</a> —— Mochi 的语法风味、类型选择、路线图;为什么不用 Python 写解释器</li><li><a href="./04-项目骨架与REPL">04-项目骨架与REPL</a> —— 测试驱动、错误位置追踪、source map——一开始就把基建搭对</li></ul><h3 id="第二层-前端-词法与语法-05-09" tabindex="-1">第二层:前端 - 词法与语法(05-09) <a class="header-anchor" href="#第二层-前端-词法与语法-05-09" aria-label="Permalink to &quot;第二层:前端 - 词法与语法(05-09)&quot;">​</a></h3><ul><li><a href="./05-词法分析">05-词法分析</a> —— Token 设计、手写状态机、注释、字符串转义、错误恢复</li><li><a href="./06-lexer生成器vs手写">06-lexer生成器vs手写</a> —— 为什么 V8 / CPython / rustc 全是手写而不是 lex/flex</li><li><a href="./07-文法基础">07-文法基础</a> —— BNF / EBNF 怎么读、LL vs LR、二义性陷阱、运算符优先级表</li><li><a href="./08-递归下降解析器">08-递归下降解析器</a> —— 一条产生式一个函数;同步点;panic mode 错误恢复</li><li><a href="./09-Pratt解析器">09-Pratt解析器</a> —— 用 binding power 数字一举搞定所有表达式优先级</li></ul><h3 id="第三层-树遍历解释器-10-15" tabindex="-1">第三层:树遍历解释器(10-15) <a class="header-anchor" href="#第三层-树遍历解释器-10-15" aria-label="Permalink to &quot;第三层:树遍历解释器(10-15)&quot;">​</a></h3><ul><li><a href="./10-AST设计">10-AST设计</a> —— 节点类型、Visitor 模式、代数数据类型(ADT)——为什么 OOP 重载在 AST 上是反模式</li><li><a href="./11-表达式求值">11-表达式求值</a> —— <code>evaluate(node, env)</code> 递归;短路 / 真值 / 隐式转换三大坑;Mochi 选 Python 路线</li><li><a href="./12-变量与作用域">12-变量与作用域</a> —— 环境链;词法 vs 动态作用域;变量解析 pass 把查找从 O(n) 优化到 O(1)</li><li><a href="./13-控制流">13-控制流</a> —— if / while / for / break / continue;异常的非局部跳转</li><li><a href="./14-函数与闭包">14-函数与闭包</a> —— 函数对象 = AST + 环境指针;为什么 JS 的 <code>var</code> 设计错了;捕获语义</li><li><strong>15 运行时错误与 REPL</strong> —— 栈追踪、source map、交互式开发的快感(<strong>本篇待补</strong>)</li></ul><h3 id="第四层-进阶语义-16-19" tabindex="-1">第四层:进阶语义(16-19) <a class="header-anchor" href="#第四层-进阶语义-16-19" aria-label="Permalink to &quot;第四层:进阶语义(16-19)&quot;">​</a></h3><ul><li><a href="./16-类与继承">16-类与继承</a> —— 对象 = 字段表 + 类指针;<code>super</code> 不是查 this 的父类,是查&quot;方法定义所在类&quot;的父类</li><li><a href="./17-模块系统">17-模块系统</a> —— 命名空间、import 语义、循环依赖;为什么 CJS 和 ESM 已经打了十年</li><li><a href="./18-类型系统初步">18-类型系统初步</a> —— 动态 / 静态 / 渐进式;Hindley-Milner 推导直觉</li><li><a href="./19-元编程入门">19-元编程入门</a> —— eval / 反射 / quote-unquote;Lisp 宏 vs Rust 宏 vs JS Proxy</li></ul><h3 id="第五层-字节码虚拟机-20-25" tabindex="-1">第五层:字节码虚拟机(20-25) <a class="header-anchor" href="#第五层-字节码虚拟机-20-25" aria-label="Permalink to &quot;第五层:字节码虚拟机(20-25)&quot;">​</a></h3><ul><li><a href="./20-为什么要VM">20-为什么要VM</a> —— 树遍历的瓶颈;编译到字节码的收益;重写 Mochi 后端</li><li><a href="./21-字节码设计">21-字节码设计</a> —— 指令集、操作数编码、常量池;反汇编工具先写好</li><li><a href="./22-栈式VM">22-栈式VM</a> —— <code>while + switch</code> 调度循环;<code>CONST</code> <code>LOAD_LOCAL</code> <code>JUMP_IF_FALSE</code>;computed goto</li><li><a href="./23-寄存器式VM">23-寄存器式VM</a> —— Lua / Dalvik 的选择;指令更少但编译器更复杂</li><li><a href="./24-编译器-AST到字节码">24-编译器-AST到字节码</a> —— 单遍编译;局部变量编号;跳转回填</li><li><a href="./25-函数调用与闭包">25-函数调用与闭包</a> —— Call frame、返回地址、upvalue 与逃逸捕获</li></ul><h3 id="第六层-运行时与未来-26-30" tabindex="-1">第六层:运行时与未来(26-30) <a class="header-anchor" href="#第六层-运行时与未来-26-30" aria-label="Permalink to &quot;第六层:运行时与未来(26-30)&quot;">​</a></h3><ul><li><a href="./26-GC基础">26-GC基础</a> —— 引用计数 vs 追踪;mark-sweep;三色标记;Mochi 手写一个</li><li><a href="./27-GC进阶">27-GC进阶</a> —— 分代 / 增量 / 并发;写屏障;为什么 V8 和 JVM 都走这条路</li><li><a href="./28-JIT心智">28-JIT心智</a> —— 模板 / 方法 / Tracing 三大流派;type specialization + IC + deopt 三件套;V8 多 tier 怎么协作</li><li><a href="./29-真实语言剖析">29-真实语言剖析</a> —— CPython / V8 / Lua / JVM 一个一个拆开,带文件名、类名、入口函数</li><li><a href="./30-从Mochi到生产语言">30-从Mochi到生产语言</a> —— WASM 后端、增量编译、LSP;你的下一步路线图</li></ul><hr><h2 id="推荐的阅读组合" tabindex="-1">推荐的阅读组合 <a class="header-anchor" href="#推荐的阅读组合" aria-label="Permalink to &quot;推荐的阅读组合&quot;">​</a></h2><p><strong>「我只想了解原理,不写代码」</strong>:01 → 02 → 14 → 16 → 26 → 28 → 29——拿到核心心智图,知道实现层在干嘛,够你跟同事白板讨论了。</p><p><strong>「我要写 DSL / 配置语言 / 模板引擎」</strong>:精读 04-09——前端这一层手痒值最高,写完一套你能解析任意小语言。再补 10、11 让你的 DSL 真能算出值。</p><p><strong>「我要懂 V8 / CPython 源码」</strong>:<strong>通读 30 篇,然后 29 反复看</strong>。前面 28 篇是给你建坐标系——读完 V8 的 <code>src/objects/map.h</code>(HiddenClass)、CPython 的 <code>Python/ceval.c</code>(字节码调度)、Lua 的 <code>src/lvm.c</code>(寄存器式 VM)都不再发懵。</p><p><strong>「我想自己写一门嵌入式脚本语言」</strong>:01 → 04 → 05-09 → 10-19 → 20-25——动手把 Mochi 抄一遍。看完能上手做 Lua 替代品级别的玩具。</p><p><strong>「我对性能感兴趣」</strong>:20 → 22 → 23 → 28 → 27——VM dispatch、寄存器 vs 栈式、JIT 的真实加速比、GC 暂停时间,全部一次看完。</p><hr><h2 id="mochi-语法速查表" tabindex="-1">Mochi 语法速查表 <a class="header-anchor" href="#mochi-语法速查表" aria-label="Permalink to &quot;Mochi 语法速查表&quot;">​</a></h2><div class="language-mochi vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mochi</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 不可变绑定 / 可变绑定</span></span>
<span class="line"><span>let x = 1</span></span>
<span class="line"><span>var y = 2</span></span>
<span class="line"><span>y = 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 函数(一等公民)</span></span>
<span class="line"><span>fn add(a, b) {</span></span>
<span class="line"><span>  return a + b</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 类(单继承,父类用 &lt; 标注)</span></span>
<span class="line"><span>class Point {</span></span>
<span class="line"><span>  init(x, y) {</span></span>
<span class="line"><span>    this.x = x</span></span>
<span class="line"><span>    this.y = y</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>  distance() {</span></span>
<span class="line"><span>    return sqrt(this.x*this.x + this.y*this.y)</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>class ColorPoint &lt; Point {</span></span>
<span class="line"><span>  init(x, y, color) {</span></span>
<span class="line"><span>    super.init(x, y)</span></span>
<span class="line"><span>    this.color = color</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 控制流(强制大括号,没有&quot;裸 if&quot;)</span></span>
<span class="line"><span>if x &gt; 0 {</span></span>
<span class="line"><span>  print(&quot;正&quot;)</span></span>
<span class="line"><span>} else if x == 0 {</span></span>
<span class="line"><span>  print(&quot;零&quot;)</span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span>  print(&quot;负&quot;)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>while x &gt; 0 { x = x - 1 }</span></span>
<span class="line"><span>for i in 0..10 { print(i) }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 模块</span></span>
<span class="line"><span>import &quot;math&quot;</span></span>
<span class="line"><span>import { sqrt, sin } from &quot;math&quot;</span></span></code></pre></div><p><strong>字节码指令名约定(全系列统一)</strong>:<code>CONST</code> <code>POP</code> <code>LOAD_LOCAL</code> <code>STORE_LOCAL</code> <code>ADD</code> <code>SUB</code> <code>MUL</code> <code>DIV</code> <code>EQ</code> <code>LT</code> <code>GT</code> <code>NOT</code> <code>JUMP</code> <code>JUMP_IF_FALSE</code> <code>CALL</code> <code>RETURN</code>。22 篇栈式 VM 给出完整 TS 实现。</p><p><strong>真值语义</strong>:<code>false</code> <code>0</code> <code>&quot;&quot;</code> <code>null</code> 为假,其他全为真——向 Python 看齐,但不让空容器自动为假。</p><p><strong>相等</strong>:<code>==</code> 是严格相等,不做 JS 那种隐式类型转换(<code>&quot;3&quot; + 4</code> 直接报错)。</p><hr><h2 id="工业级源码索引" tabindex="-1">工业级源码索引 <a class="header-anchor" href="#工业级源码索引" aria-label="Permalink to &quot;工业级源码索引&quot;">​</a></h2><p>读完 Mochi,你的下一站。<strong>每个项目给一个入口文件 + 一段说明</strong>——按这个指针进去就能开始读。</p><h3 id="cpython-——-字节码-vm-的标杆-python-自己" tabindex="-1">CPython —— 字节码 VM 的标杆,Python 自己 <a class="header-anchor" href="#cpython-——-字节码-vm-的标杆-python-自己" aria-label="Permalink to &quot;CPython —— 字节码 VM 的标杆,Python 自己&quot;">​</a></h3><p>仓库:<a href="https://github.com/python/cpython" target="_blank" rel="noreferrer"><code>python/cpython</code></a></p><table tabindex="0"><thead><tr><th>主题</th><th>文件</th><th>看什么</th></tr></thead><tbody><tr><td>字节码调度循环</td><td><a href="https://github.com/python/cpython/blob/main/Python/ceval.c" target="_blank" rel="noreferrer"><code>Python/ceval.c</code></a> <code>_PyEval_EvalFrameDefault</code></td><td>4000 行的怪兽,computed goto + IC</td></tr><tr><td>Specializing interpreter</td><td><a href="https://github.com/python/cpython/blob/main/Python/generated_cases.c.h" target="_blank" rel="noreferrer"><code>Python/generated_cases.c.h</code></a></td><td>3.11+ 自动生成的特化指令</td></tr><tr><td>PEG 文法</td><td><a href="https://github.com/python/cpython/blob/main/Grammar/python.gram" target="_blank" rel="noreferrer"><code>Grammar/python.gram</code></a></td><td>3.9+ 切到 PEG 后的源文法</td></tr><tr><td>对象 / 类型系统</td><td><a href="https://github.com/python/cpython/blob/main/Objects/typeobject.c" target="_blank" rel="noreferrer"><code>Objects/typeobject.c</code></a></td><td><code>_PyType_Lookup</code>(方法查找)、<code>super_getattro</code></td></tr><tr><td>GC</td><td><a href="https://github.com/python/cpython/blob/main/Python/gc.c" target="_blank" rel="noreferrer"><code>Python/gc.c</code></a></td><td>引用计数 + 分代追踪(循环引用)</td></tr></tbody></table><p>入门切入点:<strong>先看 <code>ceval.c</code> 里 <code>case TARGET(LOAD_FAST):</code></strong>,这就是 Mochi 22 篇那个 switch 的真身。</p><h3 id="v8-——-javascript-引擎-多-tier-jit-的代表" tabindex="-1">V8 —— JavaScript 引擎,多 tier JIT 的代表 <a class="header-anchor" href="#v8-——-javascript-引擎-多-tier-jit-的代表" aria-label="Permalink to &quot;V8 —— JavaScript 引擎,多 tier JIT 的代表&quot;">​</a></h3><p>仓库:<a href="https://github.com/v8/v8" target="_blank" rel="noreferrer"><code>v8/v8</code></a></p><table tabindex="0"><thead><tr><th>主题</th><th>文件</th><th>看什么</th></tr></thead><tbody><tr><td>Ignition 解释器</td><td><code>src/interpreter/interpreter-generator.cc</code></td><td>用 CodeStubAssembler 生成机器码模板</td></tr><tr><td>Sparkplug(baseline JIT)</td><td><code>src/baseline/</code></td><td>2021 加的 baseline tier</td></tr><tr><td>Maglev(中端 JIT)</td><td><code>src/maglev/</code></td><td>2023+ 加的中端</td></tr><tr><td>TurboFan(顶级 JIT)</td><td><code>src/compiler/pipeline.cc</code></td><td>方法 JIT 的工业标杆</td></tr><tr><td>HiddenClass(IC 基础)</td><td><code>src/objects/map.h</code> <code>src/objects/js-objects.h</code></td><td>对象 shape 系统</td></tr><tr><td>GC(Orinoco)</td><td><code>src/heap/</code></td><td>分代 + 增量 + 并发</td></tr><tr><td>解析器</td><td><code>src/parsing/parser.cc</code></td><td>手写递归下降 + 表达式 Pratt</td></tr></tbody></table><p>入门切入点:<strong><code>src/objects/map.h</code></strong> 看 HiddenClass 设计——读完你会理解为什么&quot;频繁 <code>delete obj.x</code>&quot;会让 V8 性能崩。</p><h3 id="lua-——-嵌入式语言天花板-寄存器式-vm-的教科书" tabindex="-1">Lua —— 嵌入式语言天花板,寄存器式 VM 的教科书 <a class="header-anchor" href="#lua-——-嵌入式语言天花板-寄存器式-vm-的教科书" aria-label="Permalink to &quot;Lua —— 嵌入式语言天花板,寄存器式 VM 的教科书&quot;">​</a></h3><p>仓库:<a href="https://github.com/lua/lua" target="_blank" rel="noreferrer"><code>lua/lua</code></a></p><table tabindex="0"><thead><tr><th>主题</th><th>文件</th><th>看什么</th></tr></thead><tbody><tr><td>VM 调度循环</td><td><code>src/lvm.c</code> <code>luaV_execute</code></td><td><strong>1000 行能读完</strong>——栈/寄存器混合,极其干净</td></tr><tr><td>字节码格式</td><td><code>src/lopcodes.h</code></td><td>5-bit opcode + 操作数布局</td></tr><tr><td>编译器(单遍)</td><td><code>src/lparser.c</code> <code>src/lcode.c</code></td><td>一遍生成字节码,不构 AST</td></tr><tr><td>GC</td><td><code>src/lgc.c</code></td><td>增量 mark-sweep</td></tr><tr><td>GC API(嵌入)</td><td><code>src/lapi.c</code></td><td>宿主语言怎么操作 Lua 值</td></tr></tbody></table><p>入门切入点:<strong>Lua 全仓库 ~25k 行 C</strong>——是工业级语言里<strong>最适合通读</strong>的一个。先 <code>lvm.c</code> 再 <code>lparser.c</code>,两个文件读完你的&quot;语言实现&quot;心智图就稳了。<strong>LuaJIT</strong> 在另一个仓库 <a href="https://github.com/LuaJIT/LuaJIT" target="_blank" rel="noreferrer"><code>LuaJIT/LuaJIT</code></a>,<code>src/lj_record.c</code> 是 Tracing JIT 的起点——想看 JIT 真东西必读。</p><h3 id="jvm-hotspot-——-gc-与-jit-的工业巅峰" tabindex="-1">JVM(HotSpot) —— GC 与 JIT 的工业巅峰 <a class="header-anchor" href="#jvm-hotspot-——-gc-与-jit-的工业巅峰" aria-label="Permalink to &quot;JVM(HotSpot) —— GC 与 JIT 的工业巅峰&quot;">​</a></h3><p>仓库:<a href="https://github.com/openjdk/jdk" target="_blank" rel="noreferrer"><code>openjdk/jdk</code></a></p><table tabindex="0"><thead><tr><th>主题</th><th>文件</th><th>看什么</th></tr></thead><tbody><tr><td>模板解释器</td><td><code>src/hotspot/cpu/x86/templateTable_x86.cpp</code></td><td>每条字节码对应一段手写汇编</td></tr><tr><td>C1(client JIT)</td><td><code>src/hotspot/share/c1/</code></td><td>快速 JIT,linear scan 寄存器分配</td></tr><tr><td>C2(server JIT)</td><td><code>src/hotspot/share/opto/compile.cpp</code></td><td>SSA + Sea-of-Nodes,<strong>至今无对手</strong></td></tr><tr><td>G1 GC</td><td><code>src/hotspot/share/gc/g1/</code></td><td>分代 + region + 并发</td></tr><tr><td>ZGC</td><td><code>src/hotspot/share/gc/z/</code></td><td>亚毫秒级停顿的 GC</td></tr></tbody></table><p>入门切入点:<strong>模板解释器先看</strong>——<code>templateTable_x86.cpp</code> 的 <code>iadd_template</code> 就是字节码 <code>IADD</code> 翻成的几条 x86 汇编,<strong>比抽象的 IR 直观 10 倍</strong>。</p><h3 id="其他相关" tabindex="-1">其他相关 <a class="header-anchor" href="#其他相关" aria-label="Permalink to &quot;其他相关&quot;">​</a></h3><ul><li><a href="https://github.com/munificent/craftinginterpreters" target="_blank" rel="noreferrer"><code>crafting-interpreters/craftinginterpreters</code></a> —— 《Crafting Interpreters》的 Lox jlox(tree-walk)+ clox(字节码),作者 Bob Nystrom</li><li><a href="https://github.com/thorstenball/writing-an-interpreter" target="_blank" rel="noreferrer"><code>thorstenball/writing-an-interpreter</code></a> —— Monkey 语言,Go 写的 tree-walk</li><li><a href="https://github.com/pypy/pypy" target="_blank" rel="noreferrer"><code>pypy/pypy</code></a> —— PyPy,Python 上的 Tracing JIT,看 <code>rpython/jit/metainterp/</code></li><li><a href="https://github.com/microsoft/TypeScript" target="_blank" rel="noreferrer"><code>microsoft/TypeScript</code></a> —— 解析器和类型检查器都在 <code>src/compiler/</code>,单文件 9000+ 行的 <code>parser.ts</code></li></ul><hr><h2 id="还没看-mochi-仓库" tabindex="-1">还没看 Mochi 仓库? <a class="header-anchor" href="#还没看-mochi-仓库" aria-label="Permalink to &quot;还没看 Mochi 仓库?&quot;">​</a></h2><p>GitHub: <code>mochi-lang</code>(按篇分 tag,每篇对应一个可运行版本)。<strong>没动手过的篇章不算完成</strong>——按 tag 切到对应版本、<code>pnpm test</code> 跑过、改两行代码看会不会挂——这才是&quot;看过&quot;。</p><hr><blockquote><p>30 篇看完,你应该能在白板前讲清楚:<strong>&quot;为什么 JS 的 <code>let</code> 比 <code>var</code> 安全,在解释器实现层差在哪一步&quot;</strong>、<strong>&quot;为什么 CPython 慢但 PyPy 快好几倍&quot;</strong>、<strong>&quot;为什么 Lua 用寄存器式 VM,V8 用栈式,各自取舍是什么&quot;</strong>、<strong>&quot;为什么 Go 不用引用计数,Swift 不用追踪 GC&quot;</strong>。讲清楚其中一题,这个系列就值了。</p></blockquote>`,65)])])}const g=a(r,[["render",s]]);export{u as __pageData,g as default};
